<template><section v-if="open" class="cart-panel"><div class="cart-head"><div><div class="cart-title">Shopping Cart</div><div class="cart-sub">Move To Where?</div></div><div class="cart-meta">Maker: <strong>{{ cartMaker || '-' }}</strong><br/>Model Group: <strong>{{ cartModelGroup || '-' }}</strong></div></div><div class="cart-sections"><div v-for="item in items" :key="item.key" class="cart-row"><button @click="emit('remove-item',item.key)">✕</button><strong>{{ item.name }}</strong><span>{{ item.sourceEqpId }}</span></div></div><div class="target-wrap"><select multiple :value="selectedTargetEqpIds" @change="onSelect"><option v-for="opt in targetOptions" :key="opt.eqpId" :value="opt.eqpId">{{ opt.line }} / {{ opt.team }} / {{ opt.eqpId }}</option></select></div><div class="cart-actions"><button @click="emit('clear')">Clear Cart</button><button :disabled="moving||!items.length||!selectedTargetEqpIds.length" @click="emit('move')">{{ moving?'Moving...':'Move Selected Files' }}</button></div></section></template>
<script setup lang="ts">import type { PropType } from 'vue'; type Item={key:string;kind:'cas'|'job'|'recipe';name:string;sourceEqpId:string}; type Eqp={line:string;team:string;eqpId:string;maker?:string;modelGroup?:string}; defineProps({open:Boolean,items:{type:Array as PropType<Item[]>,default:()=>[]},targetOptions:{type:Array as PropType<Eqp[]>,default:()=>[]},selectedTargetEqpIds:{type:Array as PropType<string[]>,default:()=>[]},moving:Boolean,cartMaker:String,cartModelGroup:String}); const emit=defineEmits(['set-target-eqp-ids','remove-item','clear','move']); function onSelect(e:Event){const opts=Array.from((e.target as HTMLSelectElement).selectedOptions).map(o=>o.value);emit('set-target-eqp-ids',opts)}</script>
<style scoped>.cart-panel{width:min(420px,calc(100vw - 24px));background:#fff;border:1px solid #e6e8ef;border-radius:14px;box-shadow:0 16px 36px rgba(10,20,40,.12);padding:12px;display:grid;gap:10px}.cart-head{display:flex;justify-content:space-between}.cart-title{font-weight:900}.cart-row{display:grid;grid-template-columns:32px 1fr 100px;gap:8px;border:1px solid #d8dee9;padding:6px;border-radius:8px}.target-wrap select{width:100%;height:90px}.cart-actions{display:flex;justify-content:flex-end;gap:8px}</style>
